option.value:
:root {
  --bg-main: #fdeff4;
  --bg-section: #fff7f9;
  --bg-card: #ffffff;
  --accent: #f9a8c6;
  --accent-dark: #f284b5;
  --text-main: #2a1727;
  --text-muted: #9b7c90;
  --badge-bg: #fde1ea;
  --shadow-soft: 0 18px 40px rgba(0, 0, 0, 0.08);
  --radius-large: 28px;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: "Poppins", system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  background-color: var(--bg-main);
  color: var(--text-main);
}

a {
  text-decoration: none;
  color: inherit;
}

/* ---------- NAVBAR ----------- */

.navbar {
  max-width: 1180px;
  margin: 0 auto;
  padding: 18px 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.navbar-logo {
  font-family: "Playfair Display", serif;
  font-size: 1.4rem;
  letter-spacing: 0.06em;
}

.navbar-menu {
  display: flex;
  gap: 20px;
  font-size: 0.9rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.navbar-menu a {
  position: relative;
  padding-bottom: 4px;
}

.navbar-menu a::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 0;
  height: 2px;
  background: var(--accent);
  transition: width 0.2s;
}

.navbar-menu a:hover::after {
  width: 100%;
}

.navbar-menu a.active::after {
  width: 100%;
}

.navbar-cart {
  font-size: 0.9rem;
  background: #fff;
  padding: 8px 16px;
  border-radius: 999px;
  box-shadow: 0 8px 18px rgba(0, 0, 0, 0.08);
}
.navbar-bell {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  margin-right: 10px;
  font-size: 0.9rem;
  cursor: pointer;
}

.navbar-bell-count {
  min-width: 18px;
  height: 18px;
  border-radius: 999px;
  background: #f97373;
  color: #fff;
  font-size: 0.7rem;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 5px;
}


/* ---------- HERO ----------- */

.hero {
  max-width: 1180px;
  margin: 0 auto;
  padding: 10px 24px 40px;
  display: grid;
  grid-template-columns: minmax(0, 1.1fr) minmax(0, 1.1fr);
  gap: 40px;
  align-items: center;
}

.hero-text-eyebrow {
  font-size: 0.8rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 8px;
}

.hero-title {
  font-family: "Playfair Display", serif;
  font-size: 3rem;
  line-height: 1.05;
  margin: 0 0 12px;
}

.hero-subtitle {
  font-size: 0.98rem;
  color: var(--text-muted);
  max-width: 360px;
  margin-bottom: 22px;
}

.hero-actions {
  display: flex;
  gap: 14px;
  align-items: center;
  margin-bottom: 22px;
}

.btn-primary {
  border: none;
  border-radius: 999px;
  background: var(--accent);
  color: #fff;
  padding: 11px 26px;
  font-size: 0.95rem;
  font-weight: 500;
  cursor: pointer;
  box-shadow: 0 12px 24px rgba(249, 168, 198, 0.6);
  transition: transform 0.12s ease, box-shadow 0.12s ease, background 0.12s;
}

.btn-primary:hover {
  background: var(--accent-dark);
  transform: translateY(-1px);
  box-shadow: 0 16px 30px rgba(249, 168, 198, 0.7);
}

.btn-ghost {
  border-radius: 999px;
  border: 1px solid rgba(0, 0, 0, 0.08);
  background: rgba(255, 255, 255, 0.8);
  padding: 10px 22px;
  font-size: 0.9rem;
  color: var(--text-main);
  cursor: pointer;
}

.hero-meta {
  font-size: 0.9rem;
  color: var(--text-muted);
}

.hero-image-wrap {
  position: relative;
  background: radial-gradient(circle at top, #ffe3f0 0, #fbd6e7 35%, #f7c4dc 100%);
  border-radius: var(--radius-large);
  padding: 32px;
  box-shadow: var(--shadow-soft);
  overflow: hidden;
}

.hero-image-main {
  width: 100%;
  max-width: 360px;
  margin: 0 auto 12px;
  display: block;
  border-radius: 999px;
  box-shadow: 0 18px 35px rgba(0, 0, 0, 0.18);
}

.hero-macarons-row {
  display: flex;
  justify-content: center;
  gap: 18px;
  margin-top: 8px;
}

.hero-macaron {
  width: 68px;
  height: 68px;
  border-radius: 50%;
  background: #ffeaf2;
  box-shadow: 0 10px 22px rgba(0, 0, 0, 0.14);
}

.hero-floating-label {
  position: absolute;
  right: 22px;
  top: 22px;
  background: rgba(255, 255, 255, 0.9);
  border-radius: 999px;
  padding: 8px 16px;
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.15em;
}

/* ---------- SECTION: HANDCRAFTED CAKES ----------- */

.section {
  background: #fff;
  border-radius: var(--radius-large) var(--radius-large) 0 0;
  margin-top: 10px;
  padding: 36px 24px 56px;
}

.section-inner {
  max-width: 1180px;
  margin: 0 auto;
}

.section-title {
  text-align: center;
  font-family: "Playfair Display", serif;
  font-size: 1.6rem;
  margin-bottom: 6px;
}

.section-subtitle {
  max-width: 540px;
  margin: 0 auto 24px;
  font-size: 0.92rem;
  color: var(--text-muted);
  text-align: center;
}

.products-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 18px;
}

.product-card {
  background: var(--bg-card);
  border-radius: 20px;
  padding: 12px 12px 16px;
  box-shadow: 0 12px 26px rgba(0, 0, 0, 0.06);
  display: flex;
  flex-direction: column;
}

.product-image {
  border-radius: 16px;
  background: linear-gradient(135deg, #ffe1ec, #f8d4e4);
  aspect-ratio: 4 / 3;
  margin-bottom: 10px;
  overflow: hidden;
}

.product-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.product-name {
  font-size: 0.95rem;
  font-weight: 500;
  margin-bottom: 4px;
}

.product-desc {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-bottom: 10px;
}

.product-bottom {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: auto;
  gap: 8px;
}

.product-price {
  font-weight: 600;
  font-size: 0.95rem;
}

.product-badge {
  font-size: 0.7rem;
  padding: 4px 10px;
  border-radius: 999px;
  background: var(--badge-bg);
}

.product-add-btn {
  border: none;
  border-radius: 999px;
  padding: 6px 12px;
  font-size: 0.8rem;
  background: var(--accent);
  color: #fff;
  cursor: pointer;
  box-shadow: 0 6px 14px rgba(249, 168, 198, 0.7);
  white-space: nowrap;
}

.product-add-btn:hover {
  background: var(--accent-dark);
}

/* ---------- PROMO / FOOTER ----------- */

.promo-row {
  display: grid;
  grid-template-columns: 1.1fr 1.1fr;
  gap: 24px;
  margin-top: 32px;
}

.promo-card {
  background: var(--bg-section);
  border-radius: 22px;
  padding: 20px 22px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.promo-title {
  font-family: "Playfair Display", serif;
  font-size: 1.1rem;
  margin-bottom: 6px;
}

.promo-text {
  font-size: 0.85rem;
  color: var(--text-muted);
  margin-bottom: 16px;
}

.promo-tag {
  display: inline-block;
  font-size: 0.7rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  margin-bottom: 6px;
  color: var(--accent-dark);
}

.btn-outline {
  border-radius: 999px;
  border: 1px solid rgba(0,0,0,0.12);
  background: #fff;
  padding: 9px 22px;
  font-size: 0.86rem;
  cursor: pointer;
}

.footer-mini {
  margin-top: 32px;
  font-size: 0.8rem;
  color: var(--text-muted);
  text-align: center;
}

/* ---------- RESPONSIVE ----------- */

@media (max-width: 960px) {
  .hero {
    grid-template-columns: 1fr;
  }
  .hero-image-wrap {
    order: -1;
  }
  .products-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
  .promo-row {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 640px) {
  .navbar {
    flex-direction: column;
    gap: 12px;
    align-items: flex-start;
  }
  .navbar-menu {
    flex-wrap: wrap;
    row-gap: 8px;
  }
  .hero {
    padding-inline: 16px;
  }
  .section {
    padding-inline: 16px;
  }
  .products-grid {
    grid-template-columns: 1fr;
  }
}

:root {
  --bg-main: #fdeff4;
  --bg-section: #fff7f9;
  --bg-card: #ffffff;
  --accent: #f9a8c6;
  --accent-dark: #f284b5;
  --text-main: #2a1727;
  --text-muted: #9b7c90;
  --badge-bg: #fde1ea;
  --shadow-soft: 0 18px 40px rgba(0, 0, 0, 0.08);
  --radius-large: 28px;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: "Poppins", system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  background-color: var(--bg-main);
  color: var(--text-main);
}

a {
  text-decoration: none;
  color: inherit;
}
